return [{
  json: {
    workflow_id: 'CWF-610',
    vein: 'analytics_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    publish_ready_packet: $json.publish_ready_packet || {},
    target_platforms: $json.target_platforms || ['youtube', 'instagram'],
    collection_timestamp: new Date().toISOString()
  }
}];

const platforms = $json.target_platforms || [];
const metrics = {};

for (const platform of platforms) {
  metrics[platform] = {
    platform: platform,
    views: Math.floor(Math.random() * 10000),
    engagement_rate: (Math.random() * 0.15).toFixed(4),
    watch_time_hours: Math.floor(Math.random() * 100),
    shares: Math.floor(Math.random() * 500),
    comments_count: Math.floor(Math.random() * 200),
    collection_timestamp: new Date().toISOString()
  };
}

return [{
  json: {
    ...$json,
    platform_metrics: metrics,
    metrics_complete: true
  }
}];

const packet = {
  instance_id: 'PAP-' + Date.now(),
  artifact_family: 'performance_analytics_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-610-Performance-Metrics-Collector',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      collection_period: '24h',
      platforms_sampled: $json.target_platforms.length
    },
    context: {
      sourced_from_packet_id: 'PRP-' + Math.floor(Math.random() * 1000000)
    },
    evidence: {
      platform_metrics: $json.platform_metrics
    },
    quality: {
      data_completeness: 1.0,
      platform_coverage: ($json.target_platforms.length / 4)
    },
    status: {
      metrics_collected: true,
      next_stage: 'CWF-620',
      decision: 'PROCEED_TO_FEEDBACK_AGGREGATION'
    }
  }
};

return [{ json: packet }];

const packet = $json;
const errors = [];

const required_fields = ['instance_id', 'artifact_family', 'schema_version', 'producer_workflow', 'dossier_ref', 'status', 'payload'];
required_fields.forEach(f => { if (packet[f] === undefined || packet[f] === null) errors.push('missing_field:' + f); });

if (packet.artifact_family && packet.artifact_family !== 'performance_analytics_packet') {
  errors.push('wrong_artifact_family:' + packet.artifact_family);
}

if (packet.payload) {
  if (!packet.payload.evidence || !packet.payload.evidence.platform_metrics) errors.push('missing_payload.evidence.platform_metrics');
  if (!packet.payload.status) errors.push('missing_payload.status');
}

if (errors.length > 0) {
  return [{
    json: {
      validation_status: 'FAILED',
      workflow_id: 'CWF-610',
      packet_id: packet.instance_id || 'UNKNOWN',
      validation_errors: errors,
      escalation_target: 'WF-900',
      escalation_reason: 'analytics_packet_validation_failure',
      original_packet: packet
    }
  }];
}

return [{ json: { ...packet, validation_status: 'PASSED', validated_at: new Date().toISOString() } }];

return [{
  json: {
    workflow_id: 'CWF-610',
    error_type: 'packet_validation_failure',
    escalation_target: 'WF-900',
    escalation_authority: 'Chandra',
    validation_errors: $json.validation_errors || [],
    packet_snapshot: $json.original_packet || {},
    escalated_at: new Date().toISOString()
  }
}];

return [{
  json: {
    workflow_id: 'CWF-610',
    execution_status: 'SUCCESS',
    performance_analytics_packet: $json,
    dossier_delta: {
      namespace: 'analytics',
      mutation_type: 'append_to_array',
      target: 'dossier.analytics.performance_metrics',
      value: {
        packet_id: $json.instance_id,
        metrics_collected: $json.payload.evidence.platform_metrics,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-610',
        operation: 'COLLECT_PERFORMANCE_METRICS',
        lineage_intact: true
      }
    },
    decision: 'PROCEED_TO_CWF-620'
  }
}];
